-- =====================================================================
-- ZoeCore - BG Gear Bracket Item Tier Map V1
-- =====================================================================
-- WORLD DB. Mapeia todos os itens Cruel +0 ate +4 para o futuro patch CFBG.
-- tier: 0=+0, 1=+1, 2=+2, 3=+3, 4=+4
-- category: ARMOR / WEAPON / OFFPART
START TRANSACTION;

DROP TABLE IF EXISTS `custom_bg_item_tier`;
CREATE TABLE `custom_bg_item_tier` (
  `entry` INT UNSIGNED NOT NULL,
  `tier` TINYINT UNSIGNED NOT NULL,
  `tier_label` VARCHAR(40) NOT NULL,
  `category` VARCHAR(20) NOT NULL,
  `source_kind` VARCHAR(20) NOT NULL,
  `group_name` VARCHAR(80) NOT NULL,
  `spec_name` VARCHAR(80) NOT NULL,
  `slot_name` VARCHAR(80) NOT NULL,
  `role_name` VARCHAR(80) NOT NULL,
  `material` VARCHAR(80) NOT NULL,
  `old_name` VARCHAR(255) NOT NULL,
  `new_name` VARCHAR(255) NOT NULL,
  `enabled` TINYINT UNSIGNED NOT NULL DEFAULT 1,
  PRIMARY KEY (`entry`),
  KEY `idx_tier_category` (`tier`, `category`),
  KEY `idx_enabled_tier` (`enabled`, `tier`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


COMMIT;

